#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Reescreve a seção de troubleshooting para ser amigável para iniciantes.
Separa em: BÁSICO (não precisa editar nada) e AVANÇADO (opcional).
"""

import json

def update_portuguese():
    """Update pt.json with beginner-friendly troubleshooting"""
    with open('i18n/pt.json', 'r', encoding='utf-8') as f:
        data = json.load(f)

    # Novo Passo 4 com troubleshooting amigável para iniciantes
    data['manual_step_4_content'] = """<h2>🎯 O Que Faz</h2><p>Coloca os textos traduzidos de volta dentro do jogo. Este é o passo final!</p><h2>📝 COMO USAR (Passo a Passo Visual)</h2><h3>🔹 PASSO 1: Vá para a Aba de Reinserção</h3><p>No topo da janela, clique na aba <b>"📥 3. Reinserção"</b></p><h3>🔹 PASSO 2: Escolha o Jogo Original</h3><p>• Clique em <b>"📂 Original ROM"</b> e depois <b>"Select ROM"</b><br>• Escolha o <b>mesmo arquivo de jogo</b> que você usou no início (.smc, .bin, .nds, etc.)</p><h3>🔹 PASSO 3: Escolha os Textos Traduzidos</h3><p>• Clique em <b>"📄 Translated File"</b> e depois <b>"Select File"</b><br>• Escolha o arquivo <code>*_translated.txt</code> criado no Passo 3</p><h3>🔹 PASSO 4: Dê um Nome para o Jogo Traduzido</h3><p>• No campo <b>"💾 Translated ROM (Output)"</b><br>• Digite um nome, exemplo: <code>MeuJogo_PTBR.smc</code></p><h3>🔹 PASSO 5: Criar o Jogo Traduzido</h3><p>• Aperte o botão <b>"Reinsert Translation"</b><br>• Espere 10 a 60 segundos<br>• Pronto! Seu jogo traduzido está criado!</p><h2>✅ O Que Aconteceu?</h2><ul><li>✅ Novo jogo criado com o nome que você escolheu</li><li>✅ Seu jogo original continua intacto (não foi modificado)</li><li>✅ Agora é só testar no emulador!</li></ul><h2>🎮 Como Testar o Jogo Traduzido</h2><h3>🔹 O Que é Um Emulador?</h3><p>É um programa que deixa você jogar jogos de console antigo no computador.</p><h3>🔹 Emuladores Recomendados (Baixe de Graça)</h3><ul><li><b>Super Nintendo (SNES):</b> SNES9x ou ZSNES</li><li><b>PlayStation 1:</b> ePSXe ou DuckStation</li><li><b>Game Boy Advance:</b> VisualBoy Advance</li><li><b>Nintendo DS:</b> DeSmuME ou melonDS</li></ul><h3>🔹 Como Testar (Simples!)</h3><ol><li>Abra o emulador do console certo</li><li>Clique em <b>File → Open</b> (ou Arquivo → Abrir)</li><li>Escolha seu jogo traduzido</li><li>Jogue um pouco e veja se os textos estão em português!</li></ol><h2>❓ Problemas Que Podem Aparecer (É Normal!)</h2><h3>🟢 PARA INICIANTES - Não Precisa Fazer Nada!</h3><p style="background: #1a4d1a; padding: 15px; border-left: 4px solid #4CAF50;"><b>✅ Está tudo bem se você encontrar algum problema abaixo!</b><br><br>Esses problemas são <b>NORMAIS</b> e acontecem porque:<br>• Alguns jogos têm limitações técnicas<br>• A tradução pode ficar maior que o texto original<br>• Nem todos os jogos suportam acentos<br><br><b style="font-size: 110%;">💡 O jogo vai funcionar mesmo assim! Você pode jogar normalmente!</b></p><h3>🔸 Textos Aparecendo Cortados</h3><p><b>Por que acontece:</b> A tradução em português ficou maior que o espaço do jogo.</p><p><b>Está tudo bem?</b> ✅ <b>SIM!</b> Você consegue entender o texto mesmo cortado. É normal em traduções!</p><p><i>💡 Se quiser, pode jogar assim mesmo. A maioria dos textos vai estar completa.</i></p><h3>🔸 Símbolos Estranhos em Vez de Acentos</h3><p><b>Por que acontece:</b> O jogo não tem as letras com acento (ã, ç, é, ô, etc.)</p><p><b>Está tudo bem?</b> ✅ <b>SIM!</b> Você consegue ler "voce" mesmo sem o "ê". É normal!</p><p><i>💡 Exemplo: "Você está aqui" pode aparecer como "Voce esta aqui" - dá pra entender!</i></p><h3>🔸 O Jogo Não Abre no Emulador</h3><p><b>Por que acontece:</b> Às vezes o arquivo do jogo original estava corrompido.</p><p><b>O que fazer:</b></p><ol><li>Tente usar outro emulador diferente</li><li>Se não funcionar, baixe o jogo original novamente</li><li>Refaça apenas o Passo 4 (Reinserção) - é rápido, só 1 minuto!</li></ol><h2>🔧 AVANÇADO - Só Para Quem Sabe Editar Textos (OPCIONAL!)</h2><p style="background: #4d4d1a; padding: 15px; border-left: 4px solid #FFC107;"><b>⚠️ Esta seção é só para usuários avançados!</b><br><br>Se você <b>NÃO SABE editar arquivos de texto</b>, pode pular esta parte!<br>O jogo vai funcionar normalmente sem fazer nada disso.</p><details><summary><b>🔽 Clique aqui SE você sabe usar Bloco de Notas e quer editar manualmente</b></summary><h3>🔧 Como Corrigir Textos Cortados (Avançado)</h3><ol><li>Clique com botão direito no arquivo <code>*_translated.txt</code></li><li>Escolha <b>"Abrir com... → Bloco de Notas"</b></li><li>Procure pelas frases muito longas (mais de 50 caracteres)</li><li>Encurte as frases grandes, exemplo:<br><code>Antes: "Você encontrou uma espada lendária muito poderosa"</code><br><code>Depois: "Você encontrou espada lendária"</code></li><li>Salve o arquivo (Ctrl+S)</li><li>Refaça o Passo 4 (Reinserção)</li></ol><h3>🔧 Como Trocar Acentos por Letras Normais (Avançado)</h3><ol><li>Abra <code>*_translated.txt</code> no Bloco de Notas</li><li>Use <b>Editar → Substituir</b> (ou Ctrl+H)</li><li>Substitua um por um:<br>• ã → a<br>• ç → c<br>• é → e<br>• ê → e<br>• í → i<br>• ó → o<br>• ô → o<br>• ú → u</li><li>Salve o arquivo</li><li>Refaça o Passo 4 (Reinserção)</li></ol></details><h2>💡 Dicas Importantes</h2><ul><li>✅ Sempre teste o jogo traduzido antes de compartilhar</li><li>✅ Use <b>Save States</b> do emulador para salvar em qualquer momento</li><li>✅ Guarde o arquivo <code>*_translated.txt</code> - você pode precisar depois</li><li>✅ Se der algum erro, pode refazer só o Passo 4 (é rápido!)</li><li>✅ Compartilhe seu trabalho com outros jogadores! 🎮</li></ul><h2>🎉 Parabéns!</h2><p style="background: #1a4d1a; padding: 20px; border-left: 4px solid #4CAF50; font-size: 110%;"><b>🎊 Você traduziu seu primeiro jogo!</b><br><br>Mesmo se tiver alguns textos cortados ou sem acento, você conseguiu!<br>Agora é só jogar e se divertir! 🎮✨</p>"""

    with open('i18n/pt.json', 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=4)
    print("✅ Portuguese (pt.json) updated with beginner-friendly troubleshooting!")

def update_english():
    """Update en.json with beginner-friendly troubleshooting"""
    with open('i18n/en.json', 'r', encoding='utf-8') as f:
        data = json.load(f)

    data['manual_step_4_content'] = """<h2>🎯 What It Does</h2><p>Puts translated text back inside the game. This is the final step!</p><h2>📝 HOW TO USE (Step-by-Step Visual Guide)</h2><h3>🔹 STEP 1: Go to Reinsertion Tab</h3><p>At the top of the window, click the <b>"📥 3. Reinsertion"</b> tab</p><h3>🔹 STEP 2: Choose Original Game</h3><p>• Click <b>"📂 Original ROM"</b> then <b>"Select ROM"</b><br>• Choose the <b>same game file</b> you used at the beginning (.smc, .bin, .nds, etc.)</p><h3>🔹 STEP 3: Choose Translated Text</h3><p>• Click <b>"📄 Translated File"</b> then <b>"Select File"</b><br>• Choose the <code>*_translated.txt</code> file created in Step 3</p><h3>🔹 STEP 4: Name Your Translated Game</h3><p>• In the <b>"💾 Translated ROM (Output)"</b> field<br>• Type a name, example: <code>MyGame_EN.smc</code></p><h3>🔹 STEP 5: Create Translated Game</h3><p>• Press the <b>"Reinsert Translation"</b> button<br>• Wait 10 to 60 seconds<br>• Done! Your translated game is created!</p><h2>✅ What Happened?</h2><ul><li>✅ New game created with the name you chose</li><li>✅ Your original game stays intact (not modified)</li><li>✅ Now just test it in the emulator!</li></ul><h2>🎮 How to Test Translated Game</h2><h3>🔹 What is An Emulator?</h3><p>It's a program that lets you play old console games on your computer.</p><h3>🔹 Recommended Emulators (Download Free)</h3><ul><li><b>Super Nintendo (SNES):</b> SNES9x or ZSNES</li><li><b>PlayStation 1:</b> ePSXe or DuckStation</li><li><b>Game Boy Advance:</b> VisualBoy Advance</li><li><b>Nintendo DS:</b> DeSmuME or melonDS</li></ul><h3>🔹 How to Test (Simple!)</h3><ol><li>Open the emulator for the correct console</li><li>Click <b>File → Open</b></li><li>Choose your translated game</li><li>Play a bit and see if text is in your language!</li></ol><h2>❓ Problems That May Appear (It's Normal!)</h2><h3>🟢 FOR BEGINNERS - You Don't Need to Do Anything!</h3><p style="background: #1a4d1a; padding: 15px; border-left: 4px solid #4CAF50;"><b>✅ It's okay if you find any problems below!</b><br><br>These problems are <b>NORMAL</b> and happen because:<br>• Some games have technical limitations<br>• Translation may be bigger than original text<br>• Not all games support accents<br><br><b style="font-size: 110%;">💡 The game will work anyway! You can play normally!</b></p><h3>🔸 Text Appearing Cut Off</h3><p><b>Why it happens:</b> The translation was bigger than the game's space.</p><p><b>Is it okay?</b> ✅ <b>YES!</b> You can understand the text even cut off. It's normal in translations!</p><p><i>💡 If you want, you can play like this. Most text will be complete.</i></p><h3>🔸 Weird Symbols Instead of Letters</h3><p><b>Why it happens:</b> The game doesn't have special letters (ã, ñ, é, ô, etc.)</p><p><b>Is it okay?</b> ✅ <b>YES!</b> You can read without accents. It's normal!</p><p><i>💡 Example: "Café" may appear as "Cafe" - you can still understand!</i></p><h3>🔸 Game Won't Open in Emulator</h3><p><b>Why it happens:</b> Sometimes the original game file was corrupted.</p><p><b>What to do:</b></p><ol><li>Try using a different emulator</li><li>If it doesn't work, download the original game again</li><li>Redo only Step 4 (Reinsertion) - it's fast, just 1 minute!</li></ol><h2>🔧 ADVANCED - Only For Those Who Know How to Edit Text (OPTIONAL!)</h2><p style="background: #4d4d1a; padding: 15px; border-left: 4px solid #FFC107;"><b>⚠️ This section is only for advanced users!</b><br><br>If you <b>DON'T KNOW how to edit text files</b>, you can skip this part!<br>The game will work normally without doing any of this.</p><details><summary><b>🔽 Click here IF you know how to use Notepad and want to edit manually</b></summary><h3>🔧 How to Fix Cut-Off Text (Advanced)</h3><ol><li>Right-click the <code>*_translated.txt</code> file</li><li>Choose <b>"Open with... → Notepad"</b></li><li>Look for very long sentences (more than 50 characters)</li><li>Shorten the long sentences, example:<br><code>Before: "You have found a very powerful legendary sword"</code><br><code>After: "You found legendary sword"</code></li><li>Save the file (Ctrl+S)</li><li>Redo Step 4 (Reinsertion)</li></ol><h3>🔧 How to Replace Accents with Normal Letters (Advanced)</h3><ol><li>Open <code>*_translated.txt</code> in Notepad</li><li>Use <b>Edit → Replace</b> (or Ctrl+H)</li><li>Replace one by one:<br>• ã → a<br>• ñ → n<br>• é → e<br>• ê → e<br>• í → i<br>• ó → o<br>• ú → u</li><li>Save the file</li><li>Redo Step 4 (Reinsertion)</li></ol></details><h2>💡 Important Tips</h2><ul><li>✅ Always test translated game before sharing</li><li>✅ Use emulator <b>Save States</b> to save anytime</li><li>✅ Keep the <code>*_translated.txt</code> file - you may need it later</li><li>✅ If you get an error, you can redo just Step 4 (it's fast!)</li><li>✅ Share your work with other players! 🎮</li></ul><h2>🎉 Congratulations!</h2><p style="background: #1a4d1a; padding: 20px; border-left: 4px solid #4CAF50; font-size: 110%;"><b>🎊 You translated your first game!</b><br><br>Even if there's some cut-off text or missing accents, you did it!<br>Now just play and have fun! 🎮✨</p>"""

    with open('i18n/en.json', 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=4)
    print("✅ English (en.json) updated with beginner-friendly troubleshooting!")

# Run updates
